def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > bin_capacity:
            priorities[i] = np.inf
        else:
            ratio = item / bin_capacity
            if ratio > 0.8:
                priorities[i] = -np.log(ratio) * 2
            elif ratio < 0.3:
                priorities[i] = -np.log(ratio) / 2
            else:
                priorities[i] = -np.log(ratio)
            if bin_capacity % 2 == 0:
                priorities[i] *= 0.9
            else:
                priorities[i] *= 1.1
            if priorities[i] > 1.5:
                priorities[i] = 1.5
            elif priorities[i] < 0.1:
                priorities[i] = 0.1
    return priorities
